  "path": "data/ignores/toptal/raw/audio.gitignore",
  "hash": "f000062f48a0036b054c0af50378773ea0edae04aa8318aff3abc3bf45c1e94a",
  "body": "\n### Audio ###\n*.aif\n*.iff\n*.m3u\n*.m4a\n*.mid\n*.mp3\n*.mpa\n*.ra\n*.wav\n*.wma\n*.ogg\n*.flac\n",
