    "\n### Dframe ###\n# Ignore files that are auto-generated\napp/View/templates_c/*\napp/View/cache/*\napp/View/logs/*\nweb/assets/*\nvendor\n\n# Force include\n!app/View/templates_c/.gitkeep\n!app/View/cache/.gitkeep\n!app/View/logs/.gitkeep\n!web/assets/.gitkeep\n\n# Ignore IDE\n.project\n.vscode/\n",
