  "body":
    "\n### FlashBuilder ###\n# Build and Release Folders\nbin/\nbin-debug/\nbin-release/\n.actionScriptProperties\n.flexConfig.xml\n\n# only for a non-library project\n.flexProperties\n\n# only for library project\n.flexLibProperties\n\n# Other files and folders\n.settings/\n.project/\n\n.FlexUnitSettings\n.externalToolBuilders\n.model\n\n",
