    "\n### Shopware ###\n# PhpStorm-Project\n.idea/\n\n# Cache and logs\n/var/cache/*\n/var/log/*\n!var/cache/clear_cache.sh\n!var/log/clear_cache.sh\n\n/web/cache\n!web/cache/.gitkeep\n\n/bin/*\n!bin/console\n/vendor/\n\n# User provided content\n/media/archive/\n/media/image/\n/media/music/\n/media/pdf/\n/media/temp/\n/media/unknown/\n/media/video/\n\n/files/documents/\n/files/downloads/\n\n# Caches/Proxies\n/tests/Shopware/TempFiles/\n/cache/\n\n# OS generated files\n.DS_Store\n.DS_Store?\n._*\n.Spotlight-V100\n.Trashes\nIcon?\nehthumbs.db\nThumbs.db\n\n# SASS/SCSS cache\n.sass-cache/\n",
